def get_bottom30(name):
    def get_bottom_codes(group):
        quantile_30 = group[name].quantile(q=0.3)
        return group[group[name] <= quantile_30].qscode.rename(name)
    return get_bottom_codes
def get_top30(name):
    def get_top_codes(group):
        quantile_70 = group[name].quantile(q=0.7)
        return group[group[name] >= quantile_70].qscode.rename(name)
    return get_top_codes

